body.script:
// ── DECISION TREE ─────────────────────────────────────────────
const TREE = {
  start:{
    q:"Does the situation involve an organisation handling your personal data?",
    help:"Personal data = any info that identifies you: name, email, IP, location, photos, health info, etc.",
    opts:[{l:"Yes",n:"eu_based"},{l:"No / Not sure",n:"no_data"}]
  },
  no_data:{type:"result",verdict:"likely_not",title:"GDPR May Not Apply",
    summary:"If no personal data was involved, GDPR protections do not apply.",
    rights:[],
    suggestions:["Reconsider whether any identifying information was involved.","Contact the organisation and ask for their Privacy Policy."],
    article:null},
  eu_based:{
    q:"Is the organisation based in the EU, or does it serve EU residents?",
    help:"GDPR applies to any organisation targeting EU residents — even if the company is outside the EU.",
    opts:[{l:"Yes",n:"which_right"},{l:"No",n:"outside_eu"},{l:"Not sure",n:"which_right"}]
  },
  outside_eu:{type:"result",verdict:"likely_not",title:"GDPR May Not Cover This",
    summary:"GDPR only applies to organisations in the EU or those targeting EU residents.",
    rights:[],
    suggestions:["Check if the organisation has an EU office — GDPR may still apply.","Look into your local data protection law (UK GDPR, LGPD, CCPA, etc.)."],
    article:"Article 3 — Territorial Scope"},
  which_right:{
    q:"Which of your rights do you think was violated?",
    help:"GDPR grants you several data rights. Pick the one closest to your situation.",
    opts:[
      {l:"I was never told my data was being collected",n:"transparency_violated"},
      {l:"My data was used without my consent",n:"consent_invalid"},
      {l:"I asked to delete my data — they refused",n:"erasure_violated"},
      {l:"I asked to see my data — they ignored me",n:"access_ignored"},
      {l:"My data was shared without my knowledge",n:"sharing_third_party"},
      {l:"My data was leaked in a breach",n:"breach_not_notified"},
      {l:"I want content removed from search results",n:"rtbf"}
    ]
  },
  rtbf:{type:"result",verdict:"violated",title:"Right to Be Forgotten / De-indexation",
    summary:"Under GDPR Article 17 and the Google Spain ruling (C-131/12), you can request search engines de-index personal data that is outdated, irrelevant, or disproportionate — including content linking you to past crimes.",
    rights:["Right to erasure / 'right to be forgotten' (Art. 17)","Right to object to processing (Art. 21)","Right to restriction (Art. 18)"],
    suggestions:[
      "Submit a de-indexation request to Google via g.co/legalremovals — select 'European privacy law' as the reason.",
      "Cite that the information is outdated, irrelevant, or causes disproportionate harm to your reputation.",
      "If Google refuses, escalate to your national DPA (e.g. CNIL in France, AEPD in Spain, Garante in Italy).",
      "For the original source website, also submit a separate erasure request under Article 17 to that publisher.",
      "For criminal records: many EU jurisdictions provide extra protection for spent convictions — consult a data protection lawyer."
    ],
    article:"Article 17 — Right to erasure; CJEU Case C-131/12 (Google Spain)"},
  transparency_violated:{type:"result",verdict:"violated",title:"Likely Violation: Right to Transparency",
    summary:"Organisations must provide a clear privacy notice at the time of data collection. Failing to do so is a direct GDPR breach.",
    rights:["Right to be informed (Art. 13/14)","Right to transparent processing (Art. 5)"],
    suggestions:["Send a formal written complaint requesting their legal basis for processing.","If no response within 30 days, file a complaint with your national DPA.","You may be entitled to compensation for non-material damages."],
    article:"Articles 13, 14 — Information to be provided"},
  consent_invalid:{type:"result",verdict:"violated",title:"Likely Violation: Invalid or Missing Consent",
    summary:"GDPR requires consent to be freely given, specific, informed, and unambiguous. Pre-ticked boxes or buried T&C consent are invalid.",
    rights:["Right to withdraw consent (Art. 7)","Right to object (Art. 21)"],
    suggestions:["Formally withdraw your consent in writing.","Request deletion of all data collected under invalid consent.","File a complaint with your national DPA."],
    article:"Article 7 — Conditions for consent"},
  erasure_violated:{type:"result",verdict:"violated",title:"Likely Violation: Right to Erasure Denied",
    summary:"Organisations must respond to erasure requests within 30 days. Refusal without a valid legal reason is a clear GDPR violation.",
    rights:["Right to erasure / 'right to be forgotten' (Art. 17)"],
    suggestions:["Follow up citing Article 17 GDPR explicitly.","If ignored, file a complaint with your national DPA.","You may bring a civil claim for damages under Article 82."],
    article:"Article 17 — Right to erasure"},
  access_ignored:{type:"result",verdict:"violated",title:"Violation: Subject Access Request Ignored",
    summary:"Organisations must respond to Subject Access Requests within 30 calendar days. Silence is a violation.",
    rights:["Right of access (Art. 15)"],
    suggestions:["Send a follow-up citing Article 15 and the 30-day deadline.","File a complaint with your national DPA with evidence of the original request."],
    article:"Article 15 — Right of access"},
  sharing_third_party:{type:"result",verdict:"possible",title:"Possible Violation: Unauthorised Data Sharing",
    summary:"Sharing personal data with third parties requires a valid legal basis and must be disclosed in the privacy notice.",
    rights:["Right to be informed (Art. 13/14)","Right to object (Art. 21)"],
    suggestions:["Submit a Subject Access Request asking for a list of all third parties your data was shared with.","If not disclosed or consented to, file a complaint with your DPA."],
    article:"Articles 13, 14, 26, 28"},
  breach_not_notified:{type:"result",verdict:"violated",title:"Likely Violation: Failure to Notify Data Breach",
    summary:"If a breach is likely to affect your rights, the organisation must notify you without undue delay.",
    rights:["Right to be notified of high-risk breaches (Art. 34)","Right to compensation (Art. 82)"],
    suggestions:["Contact the organisation asking for a formal incident report.","File a complaint with your national DPA.","Document any harm suffered for a potential compensation claim."],
    article:"Article 34 — Communication of breach to data subject"}
};

const VERDICTS = {
  violated:    {label:"LIKELY VIOLATED",    color:"#FF6B6B",bg:"rgba(255,107,107,.08)",border:"rgba(255,107,107,.3)"},
  possible:    {label:"POSSIBLE VIOLATION", color:"#E37E07",bg:"rgba(227,126,7,.07)",  border:"rgba(227,126,7,.25)"},
  action_needed:{label:"ACTION REQUIRED",   color:"#6B50FF",bg:"rgba(107,80,255,.08)", border:"rgba(107,80,255,.3)"},
  likely_not:  {label:"LIKELY NOT VIOLATED",color:"#00E5A0",bg:"rgba(0,229,160,.07)",  border:"rgba(0,229,160,.25)"}
};

const DPA_LIST = [
  {c:"Germany",n:"BfDI",u:"https://www.bfdi.bund.de"},
  {c:"France",n:"CNIL",u:"https://www.cnil.fr"},
  {c:"Spain",n:"AEPD",u:"https://www.aepd.es"},
  {c:"Italy",n:"Garante",u:"https://www.garanteprivacy.it"},
  {c:"Netherlands",n:"AP",u:"https://www.autoriteitpersoonsgegevens.nl"},
  {c:"Ireland",n:"DPC",u:"https://www.dataprotection.ie"},
  {c:"Poland",n:"UODO",u:"https://uodo.gov.pl"},
  {c:"Sweden",n:"IMY",u:"https://www.imy.se"},
  {c:"Belgium",n:"APD/GBA",u:"https://www.dataprotectionauthority.be"},
  {c:"Portugal",n:"CNPD",u:"https://www.cnpd.pt"}
];

// ── STATE ─────────────────────────────────────────────────────
let guidedHistory = ["start"];
let apiKey = "";
let lastAiResult = null;

// ── INIT ──────────────────────────────────────────────────────
document.addEventListener("DOMContentLoaded", () => {
  setTimeout(() => document.getElementById("card-landing").classList.add("in"), 50);
  buildDPA("ai"); buildDPA("res");

  const ta = document.getElementById("scenario-input");
  const btn = document.getElementById("btn-analyse");
  ta.addEventListener("input", () => {
    btn.disabled = !ta.value.trim() || !apiKey;
  });
});

function saveKey() {
  const k = document.getElementById("api-key-input").value.trim();
  if (!k) return;
  apiKey = k;
  document.getElementById("api-saved").style.display = "block";
  const ta = document.getElementById("scenario-input");
  document.getElementById("btn-analyse").disabled = !ta.value.trim();
}

function useExample(el) {
  document.getElementById("scenario-input").value = el.textContent.replace(/^"|"$/g,"");
  document.getElementById("btn-analyse").disabled = !apiKey;
  document.getElementById("scenario-input").focus();
}

// ── STAGE SWITCHER ────────────────────────────────────────────
function showStage(id) {
  ["landing","analysing","ai-result","guided","result"].forEach(s => {
    document.getElementById("stage-" + s).style.display = "none";
  });
  document.getElementById("stage-" + id).style.display = "block";
  const cards = {"landing":"card-landing","analysing":"card-analysing",
    "ai-result":"card-ai-result","guided":"card-guided","result":"card-result"};
  const cardId = cards[id];
  if (cardId) {
    const el = document.getElementById(cardId);
    if (el) { el.classList.remove("in"); setTimeout(() => el.classList.add("in"), 30); }
  }
  window.scrollTo({top:0, behavior:"smooth"});
}

// ── AI ANALYSIS ───────────────────────────────────────────────
async function handleAnalyse() {
  const scenario = document.getElementById("scenario-input").value.trim();
  if (!scenario || !apiKey) return;
  showStage("analysing");

  const systemPrompt = `You are a GDPR expert assistant built by IT Legal Solutions (itslegal.io), led by David Regairaz.
Analyse the user's scenario and determine which GDPR right(s) may have been violated.
Respond ONLY with a valid JSON object — no markdown, no extra text:
{
  "summary": "2-3 sentence plain-language summary of the situation and applicable GDPR framework",
  "verdict": "violated" | "possible" | "action_needed" | "likely_not",
  "verdictLabel": "short label",
  "rights": ["array of relevant GDPR rights with article numbers"],
  "actions": ["array of 3-5 concrete recommended steps"],
  "article": "primary GDPR article(s) or CJEU case reference",
  "continueToGuided": true | false,
  "guidedStartNode": "which_right" | "start" | null
}
Rules: cite exact articles and landmark CJEU cases (e.g. Google Spain C-131/12 for right to be forgotten). Be specific and practical.`;

  try {
    const res = await fetch("https://api.anthropic.com/v1/messages", {
      method:"POST",
      headers:{"Content-Type":"application/json","x-api-key":apiKey,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},
      body: JSON.stringify({
        model:"claude-sonnet-4-20250514",
        max_tokens:1000,
        system: systemPrompt,
        messages:[{role:"user",content:`Analyse this scenario: "${scenario}"`}]
      })
    });
    const data = await res.json();
    const text = (data.content||[]).map(b=>b.text||"").join("");
    const clean = text.replace(/```json|```/g,"").trim();
    const result = JSON.parse(clean);
    lastAiResult = result;
    renderAiResult(scenario, result);
    showStage("ai-result");
  } catch(e) {
    console.error(e);
    alert("Could not analyse your scenario. Please check your API key and try again, or use the guided questions.");
    showStage("landing");
  }
}

function renderAiResult(scenario, r) {
  document.getElementById("echo-text").textContent = '"' + scenario + '"';
  const v = VERDICTS[r.verdict] || VERDICTS.possible;
  const dot = document.getElementById("ai-verdict-dot");
  dot.style.background = v.color;
  document.getElementById("ai-verdict-label").textContent = r.verdictLabel || v.label;
  document.getElementById("ai-verdict-label").style.color = v.color;
  const badge = document.getElementById("ai-verdict-badge");
  badge.style.background = v.bg; badge.style.border = "1px solid " + v.border;
  document.getElementById("ai-accent").style.background = "linear-gradient(90deg,transparent," + v.color + ",transparent)";

  document.getElementById("ai-summary").textContent = r.summary;

  const rightsEl = document.getElementById("ai-rights");
  rightsEl.innerHTML = (r.rights||[]).map(ri =>
    `
§${ri}`).join("");
  document.getElementById("ai-rights-block").style.display = r.rights?.length ? "block" : "none";

  const actEl = document.getElementById("ai-actions");
  actEl.innerHTML = (r.actions||[]).map((a,i) =>
    `

${i+1}
${a}`).join("");
  document.getElementById("ai-actions-block").style.display = r.actions?.length ? "block" : "none";

  const legalRef = document.getElementById("ai-legal-ref");
  if (r.article) {
    document.getElementById("ai-article").textContent = "General Data Protection Regulation (EU) 2016/679 · " + r.article;
    legalRef.style.display = "flex";
  } else { legalRef.style.display = "none"; }

  document.getElementById("btn-continue-guided").style.display = r.continueToGuided ? "inline-flex" : "none";
}

// ── GUIDED FLOW ───────────────────────────────────────────────
function startGuided() { guidedHistory = ["start"]; renderGuided(); showStage("guided"); }
function continueGuided() {
  const node = lastAiResult?.guidedStartNode || "start";
  guidedHistory = [node];
  renderGuided(); showStage("guided");
}

function renderGuided() {
  const id = guidedHistory[guidedHistory.length - 1];
  const node = TREE[id];
  if (!node) return;

  const pct = Math.min(95, ((guidedHistory.length - 1) / 6) * 100);
  document.getElementById("progress-fill").style.width = pct + "%";
  document.getElementById("guided-step-label").innerHTML =
    `Step ${guidedHistory.length}
Guided assessment`;

  if (node.type === "result") { renderResult(node); showStage("result"); return; }

  document.getElementById("guided-question").textContent = node.q;
  const help = document.getElementById("guided-help");
  if (node.help) { help.textContent = "ℹ " + node.help; help.style.display = "block"; }
  else { help.style.display = "none"; }

  const opts = document.getElementById("guided-options");
  opts.innerHTML = node.opts.map((o,i) =>
    `
      ${String.fromCharCode(65+i)}${o.l}
    `).join("");
}

function chooseOption(nextId) {
  guidedHistory.push(nextId);
  const node = TREE[nextId];
  if (node?.type === "result") { renderResult(node); showStage("result"); }
  else { renderGuided(); }
}

function renderResult(node) {
  const v = VERDICTS[node.verdict] || VERDICTS.possible;
  document.getElementById("result-accent").style.background = "linear-gradient(90deg,transparent," + v.color + ",transparent)";
  const dot = document.getElementById("result-verdict-dot");
  dot.style.background = v.color;
  document.getElementById("result-verdict-label").textContent = v.label;
  document.getElementById("result-verdict-label").style.color = v.color;
  const badge = document.getElementById("result-verdict-badge");
  badge.style.background = v.bg; badge.style.border = "1px solid " + v.border;

  document.getElementById("result-title").textContent = node.title;
  document.getElementById("result-summary").textContent = node.summary;

  const rb = document.getElementById("result-rights-block");
  if (node.rights?.length) {
    document.getElementById("result-rights").innerHTML = node.rights.map(r =>
      `
§${r}`).join("");
    rb.style.display = "block";
  } else { rb.style.display = "none"; }

  document.getElementById("result-actions").innerHTML = (node.suggestions||[]).map((s,i) =>
    `

${i+1}
${s}`).join("");

  const legalRef = document.getElementById("result-legal-ref");
  if (node.article) {
    document.getElementById("result-article").textContent = "General Data Protection Regulation (EU) 2016/679 · " + node.article;
    legalRef.style.display = "flex";
  } else { legalRef.style.display = "none"; }
}

function guidedBack() {
  if (guidedHistory.length > 1) {
    guidedHistory.pop();
    const id = guidedHistory[guidedHistory.length - 1];
    const node = TREE[id];
    if (node?.type === "result") { renderResult(node); showStage("result"); }
    else { renderGuided(); showStage("guided"); }
  } else { restart(); }
}

// ── DPA ───────────────────────────────────────────────────────
function buildDPA(suffix) {
  const grid = document.getElementById("dpa-grid-" + suffix);
  grid.innerHTML = DPA_LIST.map(d =>
    `

${d.c}

${d.n}
    `).join("");
}

function toggleDPA(suffix) {
  const list = document.getElementById("dpa-list-" + suffix);
  const arrow = document.getElementById("dpa-arrow-" + suffix);
  const open = list.style.display === "block";
  list.style.display = open ? "none" : "block";
  arrow.style.transform = open ? "none" : "rotate(180deg)";
  arrow.style.transition = "transform 0.2s";
}

// ── RESTART ───────────────────────────────────────────────────
function restart() {
  guidedHistory = ["start"];
  lastAiResult = null;
  document.getElementById("scenario-input").value = "";
  document.getElementById("btn-analyse").disabled = true;
  showStage("landing");
}
